diff --git a/lib/libc/stdio/fileno.c b/lib/libc/stdio/fileno.c
index 66502430dc3d..ff317993c0d3 100644
--- a/lib/libc/stdio/fileno.c
+++ b/lib/libc/stdio/fileno.c
@@ -49,6 +49,9 @@ fileno(FILE *fp)
        fd = __sfileno(fp);
        FUNLOCKFILE(fp);

+       if (fd == -1)
+               errno = EBADF;
+
        return (fd);
 }
